1	import { useState, useEffect, useCallback } from "react";
2	import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
3	import { Button } from "@/components/ui/button";
4	import { useVoiceChat } from "@/hooks/use-voice-chat";
5	import { Mic, MicOff, Volume2, VolumeX, X, Loader2 } from "lucide-react";
6	import { supabase } from "@/integrations/supabase/client";
7	
8	import { cn } from "@/lib/utils";
9	
10	interface VoiceChatDialogProps {
11	  open: boolean;
12	  onOpenChange: (open: boolean) => void;
13	  userType: 'creator' | 'brand' | null;
14	  projectContext?: {
15	    name: string;
16	    description: string | null;
17	    customInstructions: string | null;
18	  } | null;
19	}
20	
21	interface Message {
22	  role: "user" | "assistant";
23	  content: string;
24	}
25	
26	export const VoiceChatDialog = ({
27	  open,
28	  onOpenChange,
29	  userType,
30	  projectContext,
31	}: VoiceChatDialogProps) => {
32	  const [messages, setMessages] = useState<Message[]>([]);
33	  const [isProcessing, setIsProcessing] = useState(false);
34	  const [currentTranscript, setCurrentTranscript] = useState("");
35	  const [autoListen, setAutoListen] = useState(true);
36	
37	  const sendToKira = useCallback(async (userMessage: string) => {
38	    if (!userMessage.trim()) return;
39	
40	    const newMessages: Message[] = [...messages, { role: "user", content: userMessage }];
41	    setMessages(newMessages);
42	    setIsProcessing(true);
43	
44	    try {
45	      const { data, error } = await supabase.functions.invoke('kira-gpt', {
46	        body: {
47	          prompt: userMessage,
48	          history: messages.slice(-10).map(m => ({ role: m.role, content: m.content })),
49	        },
50	      });
51	
52	      let assistantContent = "Sorry, I had a little trouble hearing that. Could you try again?";
53	
54	      if (!error && data?.reply) {
55	        assistantContent = data.reply;
56	      }
57	
58	      setMessages([...newMessages, { role: "assistant", content: assistantContent }]);
59	      speak(assistantContent);
60	    } catch (error) {
61	      console.error("Voice chat error:", error);
62	      const errorMsg = "Sorry, I had a little trouble hearing that. Could you try again?";
63	      setMessages([...newMessages, { role: "assistant", content: errorMsg }]);
64	      speak(errorMsg);
65	    } finally {
66	      setIsProcessing(false);
67	    }
68	  }, [messages, userType, projectContext]);
69	
70	  const handleTranscript = useCallback((text: string) => {
71	    setCurrentTranscript("");
72	    sendToKira(text);
73	  }, [sendToKira]);
74	
75	  const handleSpeakEnd = useCallback(() => {
76	    // Auto-start listening after Kira finishes speaking
77	    if (autoListen && open) {
78	      setTimeout(() => {
79	        startListening();
80	      }, 500);
81	    }
82	  }, [autoListen, open]);
83	
84	  const {
85	    isListening,
86	    isSpeaking,
87	    isSupported,
88	    startListening,
89	    stopListening,
90	    speak,
91	    stopSpeaking,
92	    transcript,
93	  } = useVoiceChat({
94	    onTranscript: handleTranscript,
95	    onSpeakEnd: handleSpeakEnd,
96	  });
97	
98	  useEffect(() => {
99	    if (transcript) {
100	      setCurrentTranscript(transcript);
101	    }
102	  }, [transcript]);
103	
104	  useEffect(() => {
105	    if (open && isSupported) {
106	      // Initial greeting
107	      const greeting = userType === 'brand' 
108	        ? "Hey! I'm Kira. How can I help with your campaign today?"
109	        : "Hey! I'm Kira. What would you like to work on today?";
110	      setMessages([{ role: "assistant", content: greeting }]);
111	      speak(greeting);
112	    } else if (!open) {
113	      setMessages([]);
114	      stopSpeaking();
115	      stopListening();
116	    }
117	  }, [open, isSupported, userType]);
118	
119	  if (!isSupported) {
120	    return (
121	      <Dialog open={open} onOpenChange={onOpenChange}>
122	        <DialogContent className="sm:max-w-md">
123	          <DialogHeader>
124	            <DialogTitle>Voice Chat Unavailable</DialogTitle>
125	          </DialogHeader>
126	          <p className="text-muted-foreground">
127	            Your browser doesn't support voice features. Please try using Chrome, Safari, or Edge.
128	          </p>
129	        </DialogContent>
130	      </Dialog>
131	    );
132	  }
133	
134	  return (
135	    <Dialog open={open} onOpenChange={onOpenChange}>
136	      <DialogContent className="sm:max-w-lg p-0 gap-0 overflow-hidden">
137	        {/* Header */}
138	        <div className="flex items-center justify-between p-4 border-b border-border/50 bg-gradient-to-r from-bronze/10 to-bronze-dark/10">
139	           <div className="flex items-center gap-3">
140	            <div>
141	              <h3 className="font-semibold">Voice Chat with Kira</h3>
142	              <p className="text-xs text-muted-foreground">
143	                {isSpeaking ? "Speaking..." : isListening ? "Listening..." : isProcessing ? "Thinking..." : "Tap mic to speak"}
144	              </p>
145	            </div>
146	          </div>
147	          <Button
148	            variant="ghost"
149	            size="icon"
150	            onClick={() => onOpenChange(false)}
151	            className="h-8 w-8"
152	          >
153	            <X className="w-4 h-4" />
154	          </Button>
155	        </div>
156	
157	        {/* Chat Display */}
158	        <div className="h-64 overflow-y-auto p-4 space-y-3 bg-muted/30">
159	          {messages.map((msg, idx) => (
160	            <div
161	              key={idx}
162	              className={cn(
163	                "flex gap-2",
164	                msg.role === "user" ? "flex-row-reverse" : ""
165	              )}
166	            >
167	              <div
168	                className={cn(
169	                  "max-w-[80%] rounded-2xl px-4 py-2 text-sm",
170	                  msg.role === "user"
171	                    ? "bg-bronze text-background rounded-tr-md"
172	                    : "bg-card border border-border/50 rounded-tl-md"
173	                )}
174	              >
175	                {msg.content}
176	              </div>
177	            </div>
178	          ))}
179	          
180	          {currentTranscript && (
181	            <div className="flex flex-row-reverse gap-2">
182	              <div className="max-w-[80%] rounded-2xl px-4 py-2 text-sm bg-bronze/50 text-background rounded-tr-md italic">
183	                {currentTranscript}...
184	              </div>
185	            </div>
186	          )}
187	          
188	          {isProcessing && (
189	            <div className="flex gap-2">
190	              <div className="bg-card border border-border/50 rounded-2xl rounded-tl-md px-4 py-2">
191	                <Loader2 className="w-4 h-4 animate-spin text-bronze" />
192	              </div>
193	            </div>
194	          )}
195	        </div>
196	
197	        {/* Voice Orb Controls */}
198	        <div className="p-6 bg-background flex flex-col items-center gap-4">
199	          {/* Animated Voice Orb */}
200	          <button
201	            onClick={isListening ? stopListening : startListening}
202	            disabled={isSpeaking || isProcessing}
203	            className={cn(
204	              "relative w-20 h-20 rounded-full flex items-center justify-center transition-all",
205	              isListening
206	                ? "bg-gradient-to-br from-bronze to-bronze-dark shadow-lg shadow-bronze/30"
207	                : isSpeaking
208	                ? "bg-gradient-to-br from-bronze/50 to-bronze-dark/50"
209	                : "bg-muted hover:bg-muted/80 border-2 border-border/50 hover:border-bronze/50",
210	              (isSpeaking || isProcessing) && "opacity-50 cursor-not-allowed"
211	            )}
212	          >
213	            {/* Pulsing rings when listening */}
214	            {isListening && (
215	              <>
216	                <span className="absolute inset-0 rounded-full bg-bronze/30 animate-ping" />
217	                <span className="absolute inset-[-8px] rounded-full border-2 border-bronze/20 animate-pulse" />
218	              </>
219	            )}
220	            
221	            {/* Speaking waves */}
222	            {isSpeaking && (
223	              <span className="absolute inset-[-8px] rounded-full border-2 border-bronze/40 animate-pulse" />
224	            )}
225	            
226	            {isListening ? (
227	              <Mic className="w-8 h-8 text-background relative z-10" />
228	            ) : isSpeaking ? (
229	              <Volume2 className="w-8 h-8 text-background relative z-10" />
230	            ) : (
231	              <MicOff className="w-8 h-8 text-muted-foreground" />
232	            )}
233	          </button>
234	
235	          <p className="text-sm text-muted-foreground text-center">
236	            {isListening 
237	              ? "Listening... Tap to stop" 
238	              : isSpeaking 
239	              ? "Kira is speaking..."
240	              : isProcessing
241	              ? "Processing your message..."
242	              : "Tap the microphone to speak"
243	            }
244	          </p>
245	
246	          {/* Mute/Stop controls */}
247	          <div className="flex items-center gap-2">
248	            {isSpeaking && (
249	              <Button
250	                variant="outline"
251	                size="sm"
252	                onClick={stopSpeaking}
253	                className="gap-2"
254	              >
255	                <VolumeX className="w-4 h-4" />
256	                Stop Speaking
257	              </Button>
258	            )}
259	            
260	            <Button
261	              variant="ghost"
262	              size="sm"
263	              onClick={() => setAutoListen(!autoListen)}
264	              className={cn(
265	                "gap-2 text-xs",
266	                autoListen ? "text-bronze" : "text-muted-foreground"
267	              )}
268	            >
269	              {autoListen ? "Auto-listen: On" : "Auto-listen: Off"}
270	            </Button>
271	          </div>
272	        </div>
273	      </DialogContent>
274	    </Dialog>
275	  );
276	};
