72	interface ChatHistory {
73	  id: string;
74	  title: string;
75	  timestamp: Date;
76	  project_id?: string | null;
77	  pinned?: boolean;
78	}
79	
80	// ── Desktop chat item with 3-dot context menu ──
81	interface DesktopChatItemProps {
82	  chat: ChatHistory;
83	  isActive: boolean;
84	  isRenaming: boolean;
85	  renameValue: string;
86	  indent?: boolean;
87	  onSelect: () => void;
88	  onRenameChange: (v: string) => void;
89	  onRenameSubmit: () => void;
90	  onRenameCancel: () => void;
91	  onStartRename: () => void;
92	  onPin: () => void;
93	  onDelete: () => void;
94	}
95	
96	function DesktopChatItem({
97	  chat, isActive, isRenaming, renameValue, indent = false,
98	  onSelect, onRenameChange, onRenameSubmit, onRenameCancel, onStartRename, onPin, onDelete,
99	}: DesktopChatItemProps) {
100	  const [hovered, setHovered] = useState(false);
101	  const showMenu = isActive || hovered;
102	
103	  return (
104	    <div
105	      onClick={() => { if (!isRenaming) onSelect(); }}
106	      onMouseEnter={() => setHovered(true)}
107	      onMouseLeave={() => setHovered(false)}
108	      style={{ position: 'relative' }}
109	      className={`flex items-center gap-2 ${indent ? 'py-2.5 pl-7 pr-8' : 'py-3.5 pl-2.5 pr-8'} rounded-lg cursor-pointer transition-all ${
110	        isActive ? 'bg-bronze/10 text-foreground' : 'text-muted-foreground hover:bg-muted/50 hover:text-foreground'
111	      }`}
112	    >
113	      <MessageSquare className={`w-${indent ? '3.5' : '4'} h-${indent ? '3.5' : '4'} flex-shrink-0 ${isActive ? 'text-bronze' : ''}`} />
114	
115	      {isRenaming ? (
116	        <input
117	          autoFocus
118	          value={renameValue}
119	          onChange={(e) => onRenameChange(e.target.value)}
120	          onKeyDown={(e) => {
121	            if (e.key === 'Enter') onRenameSubmit();
122	            if (e.key === 'Escape') onRenameCancel();
123	          }}
124	          onBlur={onRenameSubmit}
125	          onClick={(e) => e.stopPropagation()}
126	          className="flex-1 bg-transparent text-sm outline-none border-b border-bronze/50 focus:border-bronze text-foreground min-w-0"
127	        />
128	      ) : (
129	        <span className="flex-1 min-w-0 text-sm truncate">{chat.title}</span>
130	      )}
131	
132	      <DropdownMenu>
133	        <DropdownMenuTrigger asChild onClick={(e) => e.stopPropagation()}>
134	          <button
135	            style={{
136	              position: 'absolute',
137	              right: '4px',
138	              top: '50%',
139	              transform: 'translateY(-50%)',
140	              opacity: showMenu ? 1 : 0,
141	              pointerEvents: showMenu ? 'auto' : 'none',
142	              width: '24px',
143	              height: '24px',
144	              display: 'flex',
145	              alignItems: 'center',
146	              justifyContent: 'center',
147	              borderRadius: '4px',
148	              transition: 'opacity 0.15s',
149	              color: 'inherit',
150	            }}
151	          >
152	            <MoreVertical style={{ width: '14px', height: '14px' }} />
153	          </button>
154	        </DropdownMenuTrigger>
155	        <DropdownMenuContent align="end" className="w-44">
156	          <DropdownMenuItem
157	            onClick={(e) => { e.stopPropagation(); onPin(); }}
158	            className="gap-2 cursor-pointer"
159	          >
160	            {chat.pinned ? <PinOff className="w-3.5 h-3.5" /> : <Pin className="w-3.5 h-3.5" />}
161	            {chat.pinned ? 'Unpin' : 'Pin'}
162	          </DropdownMenuItem>
163	          <DropdownMenuItem
164	            onClick={(e) => { e.stopPropagation(); onStartRename(); }}
165	            className="gap-2 cursor-pointer"
166	          >
167	            <Pencil className="w-3.5 h-3.5" />
168	            Rename
169	          </DropdownMenuItem>
170	          <DropdownMenuSeparator />
171	          <DropdownMenuItem
172	            onClick={(e) => { e.stopPropagation(); onDelete(); }}
173	            className="gap-2 cursor-pointer text-destructive focus:text-destructive"
174	          >
175	            <Trash2 className="w-3.5 h-3.5" />
176	            Delete
177	          </DropdownMenuItem>
178	        </DropdownMenuContent>
179	      </DropdownMenu>
180	    </div>
181	  );
182	}
