199	function MobileChatItem({
200	  chat, isActive, isRenaming, renameValue,
201	  onSelect, onRenameChange, onRenameSubmit, onRenameCancel,
202	  onLongPress, onLongPressStart, onLongPressEnd,
203	}: MobileChatItemProps) {
