210	      onContextMenu={(e) => { e.preventDefault(); onLongPress(); }}
211	      className={`flex items-center gap-2 p-2.5 rounded-lg cursor-pointer transition-all select-none ${
212	        isActive ? 'bg-bronze/10' : 'hover:bg-muted/50'
213	      }`}
214	    >
215	      <MessageSquare className={`w-4 h-4 flex-shrink-0 ${isActive ? 'text-bronze' : 'text-muted-foreground'}`} />
216	
217	      {isRenaming ? (
218	        <input
219	          autoFocus
220	          value={renameValue}
221	          onChange={(e) => onRenameChange(e.target.value)}
222	          onKeyDown={(e) => {
223	            if (e.key === 'Enter') onRenameSubmit();
224	            if (e.key === 'Escape') onRenameCancel();
225	          }}
226	          onBlur={onRenameSubmit}
227	          onClick={(e) => e.stopPropagation()}
228	          className="flex-1 bg-transparent text-sm outline-none border-b border-bronze/50 focus:border-bronze text-foreground min-w-0"
229	        />
