232	      )}
233	
234	      <button
235	        onClick={(e) => { e.stopPropagation(); onLongPress(); }}
236	        className="p-1 rounded flex-shrink-0 text-muted-foreground/50 hover:text-muted-foreground hover:bg-muted/80 transition-all"
237	      >
238	        <MoreVertical className="w-3.5 h-3.5" />
239	      </button>
240	    </div>
241	  );
242	}
243	
244	const THINKING_STATES = [
245	  "Thinking...",
246	  "Cooking something up...",
247	  "Connecting the dots...",
248	  "Reading between the lines...",
249	  "Pulling it together...",
250	  "Working through this...",
251	  "Let me dig in...",
252	  "Weighing the details...",
253	  "Crafting your response...",
254	  "On it...",
255	  "Processing the context...",
256	  "Laying the groundwork...",
257	  "Sharpening my thoughts...",
258	  "Almost there...",
259	];
260	
261	function ThinkingIndicator() {
262	  const [stateIdx, setStateIdx] = useState(() => Math.floor(Math.random() * THINKING_STATES.length));
263	  useEffect(() => {
264	    const id = setInterval(() => setStateIdx(i => (i + 1) % THINKING_STATES.length), 2000);
265	    return () => clearInterval(id);
266	  }, []);
267	  return (
268	    <motion.div
269	      initial={{ opacity: 0, y: 8 }}
270	      animate={{ opacity: 1, y: 0 }}
271	      exit={{ opacity: 0, y: -4 }}
272	      transition={{ duration: 0.3 }}
273	      className="flex gap-3"
274	    >
275	      <div className="bg-muted rounded-2xl rounded-tl-md px-4 py-3">
276	        <div className="flex items-center gap-2.5">
277	          <div className="flex gap-1">
278	            {[0, 1, 2].map(i => (
279	              <motion.span
280	                key={i}
281	                className="block w-1.5 h-1.5 rounded-full bg-bronze"
282	                animate={{ opacity: [0.3, 1, 0.3] }}
283	                transition={{ duration: 1.2, repeat: Infinity, delay: i * 0.2 }}
284	              />
285	            ))}
286	          </div>
287	          <AnimatePresence mode="wait">
288	            <motion.span
289	              key={stateIdx}
290	              initial={{ opacity: 0, y: 4 }}
291	              animate={{ opacity: 1, y: 0 }}
292	              exit={{ opacity: 0, y: -4 }}
293	              transition={{ duration: 0.2 }}
294	              className="text-sm text-muted-foreground"
295	            >
296	              {THINKING_STATES[stateIdx]}
297	            </motion.span>
298	          </AnimatePresence>
299	        </div>
300	      </div>
301	    </motion.div>
302	  );
303	}
304	
305	function StreamingCursor() {
306	  return (
307	    <motion.span
308	      animate={{ opacity: [1, 0] }}
309	      transition={{ duration: 0.5, repeat: Infinity, repeatType: "reverse" }}
310	      className="inline-block w-0.5 h-4 bg-foreground/70 ml-0.5 align-middle"
311	    />
312	  );
313	}
