315	interface Message {
316	  role: "user" | "assistant";
317	  content: string;
318	  file?: string;
319	  timestamp?: Date;
320	}
321	
322	interface Project {
323	  id: string;
324	  name: string;
325	  description: string | null;
326	  custom_instructions: string | null;
327	  created_at: string;
328	  updated_at: string;
329	}
330	
331	type ViewMode = "chat" | "projects";
332	
333	const Kira = () => {
334	  const { toast } = useToast();
335	  const { kiraActionsToday, kiraActionsLimit } = useSubscription();
336	  const isAtKiraLimit = kiraActionsToday >= kiraActionsLimit;
337	  const [userType, setUserType] = useState<'creator' | 'brand' | null>(null);
338	  const [userId, setUserId] = useState<string | null>(null);
339	  const [isLoading, setIsLoading] = useState(false);
340	  const [isStreaming, setIsStreaming] = useState(false);
341	  const [isLoadingHistory, setIsLoadingHistory] = useState(true);
342	  const messagesEndRef = useRef<HTMLDivElement>(null);
343	
344	  useEffect(() => {
345	    window.scrollTo(0, 0);
346	  }, []);
347	
348	  const creatorGreetings = [
349	    "Hey there! Let's build something great today",
350	    "The world needs your story — let's tell it better",
351	    "Ready to turn creative vision into action?",
352	    "Your next big collaboration starts here",
353	    "Let's craft content that truly resonates"
354	  ];
355	
356	  const brandGreetings = [
357	    "Hey there! Let's find the perfect storytellers for your brand",
358	    "Ready to connect with creators who share your vision?",
