586	
587	    const { data: { session } } = await supabase.auth.getSession();
588	    const token = session?.access_token;
589	    if (!token) throw new Error("Not authenticated");
590	
591	    const response = await fetch(
592	      `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/kira-gpt`,
593	      {
594	        method: 'POST',
595	        headers: {
596	          'Content-Type': 'application/json',
597	          'Authorization': `Bearer ${token}`,
598	          'apikey': import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY,
599	        },
600	        body: JSON.stringify({ prompt: lastUserContent, history, conversationId }),
601	      }
602	    );
603	
604	    if (!response.ok) {
605	      let msg = "Couldn't reach Kira right now. Please try again!";
606	      try {
607	        const body = await response.json();
608	        if (body?.error) msg = body.error;
609	      } catch { /* ignore */ }
610	      throw new Error(msg);
611	    }
612	
613	    const contentType = response.headers.get('content-type') ?? '';
614	
615	    // Streaming path — edge function returns text/plain
616	    if (contentType.includes('text/plain') && response.body) {
617	      streamBufferRef.current = '';
618	      networkDoneRef.current = false;
619	      setMessages(prev => [...prev, { role: 'assistant', content: '', timestamp: new Date() }]);
620	      setIsStreaming(true);
621	
622	      const reader = response.body.getReader();
623	      const decoder = new TextDecoder();
624	      let fullContent = '';
625	
626	      try {
627	        while (true) {
628	          const { done, value } = await reader.read();
629	          if (done) break;
630	          const chunk = decoder.decode(value, { stream: true });
631	          fullContent += chunk;
632	          streamBufferRef.current += chunk;
633	        }
634	        networkDoneRef.current = true;
635	      } catch (err) {
636	        streamBufferRef.current = '';
637	        networkDoneRef.current = true;
638	        throw err;
639	      }
640	
641	      await saveMessage(conversationId, 'assistant', fullContent);
642	      return fullContent;
643	    }
644	
645	    // Fallback: JSON (prompt-abuse reply or unexpected content-type)
646	    const data = await response.json();
