23	  const streamRef = useRef<MediaStream | null>(null);
24	
25	  const formatDuration = (seconds: number) => {
26	    const m = Math.floor(seconds / 60);
27	    const s = seconds % 60;
28	    return `${m}:${s.toString().padStart(2, "0")}`;
29	  };
30	
31	  const startRecording = useCallback(async () => {
32	    try {
33	      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
34	      streamRef.current = stream;
35	
36	      // Set up audio analysis for waveform
37	      const audioContext = new AudioContext();
38	      const source = audioContext.createMediaStreamSource(stream);
39	      const analyser = audioContext.createAnalyser();
40	      analyser.fftSize = 64;
41	      source.connect(analyser);
42	      analyserRef.current = analyser;
43	
44	      // Pick a supported mime type
45	      const mimeType = ["audio/webm;codecs=opus", "audio/webm", "audio/ogg;codecs=opus", "audio/mp4", ""]
46	        .find((t) => t === "" || MediaRecorder.isTypeSupported(t))!;
47	
48	      const mediaRecorder = new MediaRecorder(stream, mimeType ? { mimeType } : undefined);
49	      mediaRecorderRef.current = mediaRecorder;
50	      chunksRef.current = [];
51	
52	      mediaRecorder.ondataavailable = (e) => {
53	        if (e.data.size > 0) chunksRef.current.push(e.data);
54	      };
55	
56	      mediaRecorder.onstop = () => {
57	        const actualType = mediaRecorder.mimeType || "audio/webm";
58	        const blob = new Blob(chunksRef.current, { type: actualType });
59	        setAudioBlob(blob);
60	        stream.getTracks().forEach((t) => t.stop());
61	      };
62	
63	      mediaRecorder.start(100);
64	      setIsRecording(true);
65	      setDuration(0);
66	      setWaveformValues([]);
67	
68	      // Timer
69	      timerRef.current = setInterval(() => {
70	        setDuration((d) => d + 1);
71	      }, 1000);
72	
